<?php
namespace App\Http\Controllers\CommandCenter\Customers; use App\Http\Controllers\Controller; use App\Models\Customers\Customer; use App\Repositories\Customers\CustomerDashboardRepository; use App\Services\Customers\CustomerInsightService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\View\View;
class CustomerIntelligenceController extends Controller { public function birthdays(Request $r,CustomerDashboardRepository $repo):View{$settings=$repo->settings($r->user()->company_id);return view('command-center.customers.intelligence.list',['title'=>'Birthday Reminders','customers'=>$repo->birthdays($r->user()->company_id,$settings->birthday_reminder_days_before),'kind'=>'birthday']);} public function inactive(Request $r,CustomerDashboardRepository $repo):View{return view('command-center.customers.intelligence.list',['title'=>'Inactive Customers','customers'=>$repo->flagged($r->user()->company_id,'is_inactive_90_days'),'kind'=>'inactive']);} public function lost(Request $r,CustomerDashboardRepository $repo):View{return view('command-center.customers.intelligence.list',['title'=>'Lost Customers','customers'=>$repo->flagged($r->user()->company_id,'is_lost_customer'),'kind'=>'lost']);} public function returns(Request $r,CustomerDashboardRepository $repo):View{return view('command-center.customers.intelligence.list',['title'=>'Frequent Return Customers','customers'=>$repo->flagged($r->user()->company_id,'is_frequent_returner'),'kind'=>'returns']);} public function insights(Request $r):View{return view('command-center.customers.insights',['customers'=>Customer::query()->with('insight')->where('company_id',$r->user()->company_id)->whereHas('insight')->orderByDesc('total_purchase_amount')->paginate(20)]);} public function refresh(Request $r,CustomerInsightService $service):RedirectResponse{$service->refreshCompany($r->user()->company_id,$r->user());return back()->with('status','Rule-based customer insights refreshed.');} }
